test("ModellingKind XML round-trip OK", () => {
  const instance = TestCommonXmlization.loadMaximalSubmodel();

  const xmlText = AasXmlization.toXmlString(instance);
  const anotherOrError = AasXmlization.fromXmlString(xmlText);
  expect(anotherOrError.error).toBeNull();

  const casted = AasTypes.asSubmodel(anotherOrError.mustValue());
  expect(casted).not.toBeNull();
  expect(casted.kind).toStrictEqual(
    instance.kind
  );
});

test("ModellingKind XML deserialization fail", () => {
  const instance = TestCommonXmlization.loadMaximalSubmodel();
  const xmlText = AasXmlization.toXmlString(instance);

  const regex = new RegExp(
    `(<${"kind"}>)([^<]*)(</${"kind"}>)`
  );
  const brokenXmlText = xmlText.replace(
    regex,
    `$1${"invalid-literal"}$3`
  );

  expect(brokenXmlText).not.toStrictEqual(xmlText);

  const anotherOrError = AasXmlization.fromXmlString(brokenXmlText);
  expect(anotherOrError.error).not.toBeNull();
});

